type HttpMethod = 'GET' | 'POST' | 'PUT' | 'DELETE';

interface RequestOptions {
  method?: HttpMethod;
  body?: any;
  headers?: Record<string, string>;
  params?: Record<string, string | number | undefined>;
}

export class ApiError extends Error {
  status: number;
  data: any;

  constructor(message: string, status: number, data?: any) {
    super(message);
    this.name = 'ApiError';
    this.status = status;
    this.data = data;
  }
}

async function request<T = any>(url: string, options: RequestOptions = {}): Promise<T> {
  const method = options.method || 'GET';
  const headers = new Headers(options.headers);

  // Set Content-Type if JSON payload
  if (options.body && !(options.body instanceof FormData)) {
    headers.set('Content-Type', 'application/json');
  }

  // Construct query string
  let targetUrl = url;
  if (options.params) {
    const searchParams = new URLSearchParams();
    Object.entries(options.params).forEach(([key, val]) => {
      if (val !== undefined) {
        searchParams.append(key, String(val));
      }
    });
    const queryString = searchParams.toString();
    if (queryString) {
      targetUrl = `${url}?${queryString}`;
    }
  }

  const response = await fetch(targetUrl, {
    method,
    headers,
    body: options.body && !(options.body instanceof FormData) 
      ? JSON.stringify(options.body) 
      : options.body,
  });

  let data: any;
  const contentType = response.headers.get('content-type');
  if (contentType && contentType.includes('application/json')) {
    data = await response.json();
  } else {
    data = await response.text();
  }

  if (!response.ok) {
    const errorMsg = data?.message || `HTTP Error ${response.status}: ${response.statusText}`;
    throw new ApiError(errorMsg, response.status, data);
  }

  return data as T;
}

export const apiClient = {
  get<T = any>(url: string, params?: Record<string, string | number | undefined>, headers?: Record<string, string>) {
    return request<T>(url, { method: 'GET', params, headers });
  },
  post<T = any>(url: string, body?: any, headers?: Record<string, string>) {
    return request<T>(url, { method: 'POST', body, headers });
  },
  put<T = any>(url: string, body?: any, headers?: Record<string, string>) {
    return request<T>(url, { method: 'PUT', body, headers });
  },
  delete<T = any>(url: string, headers?: Record<string, string>) {
    return request<T>(url, { method: 'DELETE', headers });
  }
};
